// src/pages/admin/AdminDashboard.js
import React, { useState } from "react";
import { Box, Grid, Paper, Typography } from "@mui/material";

export default function AdminDashboard() {
  // Static data for demo purposes
  const [overview] = useState({
    users: 10,
    riders: 5,
    approvedCaptains: 4,
    pendingCaptains: 1,
    rides: 7,
  });

  const cards = [
    { label: "Users", value: overview.users },
    { label: "Riders", value: overview.riders },
    { label: "Approved Captains", value: overview.approvedCaptains },
    { label: "Pending Captains", value: overview.pendingCaptains },
    { label: "Rides", value: overview.rides },
  ];

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>

      <Grid container spacing={2}>
        {cards.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Paper
              sx={{
                p: 3,
                textAlign: "center",
                boxShadow: 3,
                borderRadius: 2,
                backgroundColor: "#f5f5f5",
              }}
            >
              <Typography variant="subtitle1" color="textSecondary">
                {card.label}
              </Typography>
              <Typography variant="h5" fontWeight="bold">
                {card.value}
              </Typography>
            </Paper>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
}
